import { useEffect, useState } from "react";
import API from "../../api/axios";
// import DashboardLayout from "../../layouts/DashboardLayout";
import {
  Button,
  TextField,
  Typography,
  Box,
  Card,
  CardContent,
  IconButton,
  InputAdornment,
} from "@mui/material";
import { Visibility, VisibilityOff } from "@mui/icons-material";
import { useNavigate } from "react-router-dom";

export default function Projects() {
  const navigate = useNavigate();

  // 🔥 STATES
  const [projects, setProjects] = useState([]);
  const [showPassword, setShowPassword] = useState(false);

  const [projectForm, setProjectForm] = useState({
    name: "",
    description: "",
    start_date: "",
    end_date: "",
  });

  const [userForm, setUserForm] = useState({
    username: "",
    password: "",
    project_id: "",
  });

  // 🔥 FETCH PROJECTS
  const fetchProjects = async () => {
    const res = await API.get("projects/");
    setProjects(res.data);
  };

  useEffect(() => {
    fetchProjects();
  }, []);

  // 🔥 CREATE PROJECT
  const createProject = async () => {
    await API.post("projects/create/", projectForm);
    alert("Project Created ✅");
    fetchProjects();
  };

  // 🔥 CREATE USER
  const createProjectUser = async () => {
    await API.post("create-user/", userForm);
    alert("User Added ✅");
  };

  return (
    <DashboardLayout>
      <Box
        sx={{
          display: "flex",
          gap: 4,
          flexWrap: "wrap",
        }}
      >
        {/* ================= LEFT CARD ================= */}
        <Card
          sx={{
            flex: 1,
            minWidth: 320,
            p: 2,
            borderRadius: 4,
            background: "linear-gradient(135deg, #1e3c72, #2a5298)",
            color: "#fff",
            boxShadow: "0 20px 40px rgba(0,0,0,0.3)",
            transform: "perspective(1000px) rotateX(5deg)",
            transition: "0.4s",
            "&:hover": {
              transform: "perspective(1000px) rotateX(0deg) scale(1.02)",
            },
          }}
        >
          <CardContent>
            <Typography variant="h6">Create Project</Typography>

            <TextField
              fullWidth
              label="Project Name"
              margin="normal"
              InputLabelProps={{ style: { color: "#fff" } }}
              sx={{ input: { color: "#fff" } }}
              onChange={(e) =>
                setProjectForm({ ...projectForm, name: e.target.value })
              }
            />

            <TextField
              fullWidth
              label="Project Description"
              margin="normal"
              InputLabelProps={{ style: { color: "#fff" } }}
              sx={{ input: { color: "#fff" } }}
              onChange={(e) =>
                setProjectForm({
                  ...projectForm,
                  description: e.target.value,
                })
              }
            />

            <TextField
              fullWidth
              type="date"
              margin="normal"
              InputLabelProps={{ shrink: true }}
              onChange={(e) =>
                setProjectForm({
                  ...projectForm,
                  start_date: e.target.value,
                })
              }
            />

            <TextField
              fullWidth
              type="date"
              margin="normal"
              InputLabelProps={{ shrink: true }}
              onChange={(e) =>
                setProjectForm({
                  ...projectForm,
                  end_date: e.target.value,
                })
              }
            />

            <Button
              fullWidth
              variant="contained"
              sx={{
                mt: 2,
                background: "linear-gradient(45deg, #00c6ff, #0072ff)",
              }}
              onClick={createProject}
            >
              CREATE PROJECT
            </Button>
          </CardContent>
        </Card>

        {/* ================= RIGHT CARD ================= */}
        <Card
          sx={{
            flex: 1,
            minWidth: 320,
            p: 3,
            borderRadius: 4,
            background: "linear-gradient(135deg, #0f2027, #203a43)",
            color: "#fff",
            boxShadow: "0 20px 40px rgba(0,0,0,0.3)",
            transform: "perspective(1000px) rotateX(5deg)",
            transition: "0.4s",
            "&:hover": {
              transform: "perspective(1000px) rotateX(0deg) scale(1.02)",
            },
          }}
        >
          <CardContent>
            {/* TITLE */}
            <Typography
              variant="h5"
              textAlign="center"
              mb={3}
              fontWeight="bold"
            >
              Create Project User
            </Typography>

            {/* USERNAME */}
            <TextField
              fullWidth
              label="Username"
              margin="normal"
              InputLabelProps={{ style: { color: "#fff" } }}
              sx={{ input: { color: "#fff" } }}
              onChange={(e) =>
                setUserForm({ ...userForm, username: e.target.value })
              }
            />

            {/* PASSWORD */}
            <TextField
              fullWidth
              label="Password"
              type={showPassword ? "text" : "password"}
              margin="normal"
              InputLabelProps={{ style: { color: "#fff" } }}
              sx={{ input: { color: "#fff" } }}
              onChange={(e) =>
                setUserForm({ ...userForm, password: e.target.value })
              }
              InputProps={{
                endAdornment: (
                  <InputAdornment position="end">
                    <IconButton onClick={() => setShowPassword(!showPassword)}>
                      {showPassword ? <VisibilityOff /> : <Visibility />}
                    </IconButton>
                  </InputAdornment>
                ),
              }}
            />

            {/* BUTTONS */}
            <Box sx={{ display: "flex", gap: 2, mt: 4 }}>
              <Button
                fullWidth
                variant="contained"
                sx={{
                  py: 1.5,
                  fontWeight: "bold",
                  borderRadius: 2,
                  background: "linear-gradient(45deg, #00c6ff, #0072ff)",
                }}
                onClick={createProjectUser}
              >
                CREATE PROJECT USER
              </Button>

              <Button
                fullWidth
                variant="outlined"
                sx={{
                  py: 1.5,
                  fontWeight: "bold",
                  borderRadius: 2,
                  color: "#fff",
                  borderColor: "#fff",
                }}
                onClick={() => alert("Add User Clicked")}
              >
                ADD USER
              </Button>
            </Box>
          </CardContent>
        </Card>
      </Box>

      {/* ================= PROJECT LIST BUTTON ================= */}
      <Box mt={6} textAlign="center">
        <Button
          variant="contained"
          sx={{
            px: 6,
            py: 1.5,
            borderRadius: 3,
            fontSize: "16px",
            background: "linear-gradient(45deg, #00c6ff, #0072ff)",
            boxShadow: "0 10px 25px rgba(0,0,0,0.3)",
          }}
          onClick={() => navigate("/admin/projects/list")}
        >
          VIEW PROJECT LIST
        </Button>
      </Box>
    </DashboardLayout>
  );
}
